import time, httpx

# ✗ Wrong — time.sleep and requests.get block the event loop;
# all other requests stall while this handler waits.
@app.get("/slow")
async def slow_handler():
    time.sleep(2)               # blocks event loop!
    r = requests.get("...")     # blocks event loop!
    return {"data": r.json()}

# ✓ Correct option A: use async libraries
@app.get("/fast")
async def fast_handler():
    async with httpx.AsyncClient() as client:
        r = await client.get("...")
    return {"data": r.json()}

# ✓ Correct option B: offload to thread pool for unavoidable sync code
import asyncio
@app.get("/thread-pool")
async def threaded():
    result = await asyncio.to_thread(blocking_function, arg1, arg2)
    return {"data": result}

from pydantic import BaseModel

class UserInDB(BaseModel):
    id: str
    email: str
    hashed_password: str  # must NOT be exposed!

# ✗ Wrong — returns hashed_password to client
@app.get("/users/{id}")
async def get_user(id: str) -> UserInDB:
    return await db.get_user(id)

class UserOut(BaseModel):
    id: str
    email: str  # no hashed_password

# ✓ Correct — response_model filters to only declared fields
@app.get("/users/{id}", response_model=UserOut)
async def get_user(id: str):
    return await db.get_user(id)

from fastapi import Request
from fastapi.exceptions import RequestValidationError
from fastapi.responses import JSONResponse

@app.exception_handler(RequestValidationError)
async def validation_error_handler(request: Request, exc: RequestValidationError):
    return JSONResponse(
        status_code=422,
        content={
            "code": "VALIDATION_ERROR",
            "detail": "Request failed validation",
            "errors": exc.errors(),
        },
    )

@app.exception_handler(Exception)
async def unhandled_error_handler(request: Request, exc: Exception):
    # Log the full traceback here
    import traceback; traceback.print_exc()
    return JSONResponse(
        status_code=500,
        content={"code": "INTERNAL_ERROR", "detail": "An unexpected error occurred"},
    )
